section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "claude-advanced-features-output",
  "required": [
    "features_enabled",
    "model_id",
    "cache_hit_ratio",
    "forbidden_seen"
  ],
  "properties": {
    "features_enabled": {
      "description": "Subset of {extended_thinking, prompt_caching, batch_api, computer_use}."
    },
    "model_id": {
      "description": "Full-date pinned model id e.g. claude-opus-4-5-20251101."
    },
    "extended_thinking": {
      "description": "Object with budget_tokens, max_tokens, temperature (must be absent)."
    },
    "prompt_caching": {
      "description": "Object with cached_prefix_tokens, hit_ratio_target."
    },
    "batch_api": {
      "description": "Object with poll_interval_seconds, custom_id_source."
    },
    "computer_use": {
      "description": "Object with sandbox_kind, max_iterations, action_timeout_seconds."
    },
    "cache_hit_ratio": {
      "description": "Observed cache_read_input_tokens / input_tokens over a 100-call window."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
